// Some portions generated by Co-Pilot
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.util.Properties;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class StorePropertiesTest {

	@Test
	void saveAndLoadRoundTripsPersistedValues(@TempDir File dir) {
		StoreProperties properties = new StoreProperties(dir)
				.setVersion("1")
				.setTripleIndexes("spoc,posc");

		properties.save();

		StoreProperties loaded = new StoreProperties(dir);
		loaded.load();

		assertTrue(new File(dir, "store.properties").isFile());
		assertEquals("1", loaded.getVersion());
		assertEquals("spoc,posc", loaded.getTripleIndexes());
	}

	@Test
	void loadAndSaveRetainsTripleTermIndexes(@TempDir File dir) throws Exception {
		Properties original = new Properties();
		original.setProperty(StoreProperties.VERSION_KEY, "1");
		original.setProperty(StoreProperties.INDEXES_KEY, "spoc,posc");
		original.setProperty(StoreProperties.TRIPLE_TERM_INDEXES_KEY, "spoc");
		try (FileOutputStream out = new FileOutputStream(new File(dir, StoreProperties.FILE_NAME))) {
			original.store(out, "test");
		}

		StoreProperties loaded = new StoreProperties(dir);
		assertTrue(loaded.load());
		loaded.setTripleIndexes("spoc,posc");
		loaded.save();

		Properties persisted = new Properties();
		try (FileInputStream in = new FileInputStream(new File(dir, StoreProperties.FILE_NAME))) {
			persisted.load(in);
		}

		assertEquals("spoc", persisted.getProperty(StoreProperties.TRIPLE_TERM_INDEXES_KEY));
	}

	@Test
	void exposesTripleTermIndexAccessors() {
		assertDoesNotThrow(() -> StoreProperties.class.getDeclaredMethod("getTripleTermIndexes"));
		assertDoesNotThrow(() -> StoreProperties.class.getDeclaredMethod("setTripleTermIndexes", String.class));
	}
}
